if &OqueFazer <> 'M' HostWebServiceJaspiADM.Call(&EmpCod, &EmpWebHost, &EmpWebBaseUrl, &EmpWebPor)
&HttpClient.Host = &EmpWebHost //servidor sistema.efrete.com &HttpClient.Port = &EmpWebPor &HttpClient.BaseUrl = &EmpWebBaseUrl //diretório virtual do serviço &HttpClient.Secure = 0 //false
&LongVarchar = '<soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/" xmlns:adm="ADM_JASPI">' &LongVarchar += ' <soapenv:Header/>' &LongVarchar += ' <soapenv:Body>' &LongVarchar += ' <adm:ppJASPI_DuplicatasPaga.Execute>' &LongVarchar += ' <adm:Sdtduplicatas> ' &LongVarchar += ' <adm:Duplicatas> '
//NAVEGA SDT For &ppJASPI_DuplicatasPagasdtDuplicatasitem in &ppJASPI_DuplicatasPagasdtDuplicatas.Duplicatas.Items &LongVarchar += ' <adm:Item> ' &LongVarchar += format(' <adm:CliCodSync>%1</adm:CliCodSync> ', trim(upper(&ppJASPI_DuplicatasPagasdtDuplicatasitem.CliCodSync))) &LongVarchar += format(' <adm:CreDtaVct>%1</adm:CreDtaVct> ', trim(ToformattedString(&ppJASPI_DuplicatasPagasdtDuplicatasitem.CreDtaVct))) &LongVarchar += format(' <adm:CreVlrDup>%1</adm:CreVlrDup> ', trim(toformattedString(&ppJASPI_DuplicatasPagasdtDuplicatasitem.CreVlrDup))) &LongVarchar += format(' <adm:CreSync>%1</adm:CreSync> ', trim(&ppJASPI_DuplicatasPagasdtDuplicatasitem.CreSync)) &LongVarchar += format(' <adm:CreCod>%1</adm:CreCod> ', trim(str(&ppJASPI_DuplicatasPagasdtDuplicatasitem.CreCod))) &LongVarchar += ' </adm:Item> ' Endfor
&LongVarchar += ' </adm:Duplicatas>' &LongVarchar += ' </adm:Sdtduplicatas>' &LongVarchar += ' </adm:ppJASPI_DuplicatasPaga.Execute>' &LongVarchar += ' </soapenv:Body>' &LongVarchar += '</soapenv:Envelope>'
//ADICIONANDO CABEÇALHO DE COMUNICAÇÃO &HttpClient.AddHeader('Content-Type','text/xml;charset=UTF-8') &HttpClient.AddHeader('SOAPAction', '"ADM_JASPIaction/APPJASPI_DUPLICATASPAGA.Execute"') &HttpClient.AddString(&LongVarchar) //ADICIONANDO PARAMETROS &HttpClient.Execute('POST','appjaspi_duplicataspaga.aspx') //FAZENDO POST DE COSNULTA
If &HttpClient.ErrCode = 0 //sem erro de comunicação &LongVarchar = '' &longvarchar = &HttpClient.toString() &longvarchar = strReplace(&longvarchar,'<?xml version = "1.0" encoding = "utf-8"?>', '') &longvarchar = strReplace(&longvarchar,'<SOAP-ENV:Envelope xmlns:SOAP-ENV="http://schemas.xmlsoap.org/soap/envelope/" xmlns:xsd="http://www.w3.org/2001/XMLSchema" xmlns:SOAP-ENC="http://schemas.xmlsoap.org/soap/encoding/" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance">', '') &longvarchar = strReplace(&longvarchar,'<SOAP-ENV:Body>', '') &longvarchar = strReplace(&longvarchar,'</SOAP-ENV:Body>', '') &longvarchar = strReplace(&longvarchar,'</SOAP-ENV:Envelope>', '')
&longvarchar = strReplace(&longvarchar,'<ppJASPI_DuplicatasPaga.ExecuteResponse xmlns="ADM_JASPI">', '') &longvarchar = strReplace(&longvarchar,'</ppJASPI_DuplicatasPaga.ExecuteResponse>', '') &longvarchar = strReplace(&longvarchar,'Outsdtduplicatas', 'sdtDuplicatas')
// &XmlWriter.Open('recebido.xml') // &XmlWriter.WriteRawText(&LongVarchar) // &XmlWriter.Close()
&outppJASPI_DuplicatasPagasdtDuplicatas.FromXml(&LongVarchar)
// &XmlWriter.Open('FormatadoXML.xml') // &XmlWriter.WriteRawText(&outppJASPI_DuplicatasPagasdtDuplicatas.ToXml()) // &XmlWriter.Close()
do 'atualizaDuplicatas'
//&Erro = 0 Else //&Erro = 1 msg(&HttpClient.ErrDescription, status) EndIf Else For &ppJASPI_DuplicatasPagasdtDuplicatasitem in &ppJASPI_DuplicatasPagasdtDuplicatas.Duplicatas.Items if &ppJASPI_DuplicatasPagasdtDuplicatasItem.CreSync = 'S' For Each Order EmpCod, FilCod, CreCod Where EmpCod = &EmpCod Where FilCod = &FilCod Where CreAdmCod = &ppJASPI_DuplicatasPagasdtDuplicatasItem.CreCod
CreAdmLib = 'S' EndFor Endif
EndFor
Commit EndIF
sub 'atualizaDuplicatas' For &ppJASPI_DuplicatasPagasdtDuplicatasItem in &outppJASPI_DuplicatasPagasdtDuplicatas.Duplicatas.Items if &ppJASPI_DuplicatasPagasdtDuplicatasItem.CreSync = 'S' For Each Order EmpCod, FilCod, CreCod Where EmpCod = &EmpCod Where FilCod = &FilCod Where CreAdmCod = &ppJASPI_DuplicatasPagasdtDuplicatasItem.CreCod
CreAdmLib = 'S' EndFor Endif
EndFor
Commit EndSub
